    private function base_dir() {
        $upload = wp_upload_dir();
        $base_dir = trailingslashit($upload['basedir']) . 'user-files';
        $base_url = trailingslashit($upload['baseurl']) . 'user-files';
        return [$base_dir, $base_url];
    }

    private function user_dir($user_id) {
        [$base_dir, $base_url] = $this->base_dir();
        $dir = trailingslashit($base_dir) . (int)$user_id;
        $url = trailingslashit($base_url) . (int)$user_id;
        return [$dir, $url];
    }

    private function ensure_dir($dir) {
        if (!file_exists($dir)) {
            wp_mkdir_p($dir);
        }
        if (!is_dir($dir) || !is_writable($dir)) {
            return false;
        }
        return true;
    }

    private function allowed_mimes() {
        return [
            'jpg'  => 'image/jpeg',
            'jpeg' => 'image/jpeg',
            'png'  => 'image/png',
            'gif'  => 'image/gif',
            'webp' => 'image/webp',
            'pdf'  => 'application/pdf',
            'doc'  => 'application/msword',
            'docx' => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'xls'  => 'application/vnd.ms-excel',
            'xlsx' => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'txt'  => 'text/plain',
        ];
    }

    private function file_ext_from_name($name) {
        $name = (string)$name;
        $ext = strtolower(pathinfo($name, PATHINFO_EXTENSION));
        return $ext;
    }

    private function sanitize_filename_strict($filename) {
        $filename = sanitize_file_name($filename);
        $filename = preg_replace('/[^A-Za-z0-9\-\._]/', '-', $filename);
        $filename = preg_replace('/-+/', '-', $filename);
        $filename = trim($filename, '-');
        if ($filename === '') $filename = 'file';
        return $filename;
    }

    private function unique_filename($dir, $filename) {
        $filename = $this->sanitize_filename_strict($filename);
        $ext = $this->file_ext_from_name($filename);
        $name = $filename;
        if ($ext) {
            $base = substr($filename, 0, -1 * (strlen($ext) + 1));
        } else {
            $base = $filename;
        }
        $candidate = $name;
        $i = 1;
        while (file_exists(trailingslashit($dir) . $candidate)) {
            $suffix = '-' . $i;
            $candidate = $ext ? ($base . $suffix . '.' . $ext) : ($base . $suffix);
            $i++;
        }
        return $candidate;
    }

    private function redirect_with_message($ok, $msg) {
        $url = remove_query_arg(['mufu_ok','mufu_msg']);
        $url = add_query_arg([
            'mufu_ok' => $ok ? 1 : 0,
            'mufu_msg' => rawurlencode($msg),
        ], $url);
        wp_safe_redirect($url);
        exit;
    }

    public function handle_upload() {
        if (empty($_POST['mufu_action']) || $_POST['mufu_action'] !== 'upload') return;
        if (!is_user_logged_in()) $this->redirect_with_message(false, 'You must be logged in.');

        if (empty($_POST[self::NONCE_FIELD]) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST[self::NONCE_FIELD])), self::NONCE_ACTION)) {
            $this->redirect_with_message(false, 'Security check failed.');
        }

        $type = !empty($_POST['mufu_type']) ? sanitize_text_field(wp_unslash($_POST['mufu_type'])) : 'document';
        if (!in_array($type, ['document','profile'], true)) $type = 'document';

        $max_mb = !empty($_POST['mufu_max_mb']) ? (int)$_POST['mufu_max_mb'] : 20;
        $max_mb = max(1, min(200, $max_mb));
        $max_bytes = $max_mb * 1024 * 1024;

        if (empty($_FILES[self::FORM_FIELD])) {
            $this->redirect_with_message(false, 'No file received.');
        }

        $user_id = get_current_user_id();
        [$dir, $url] = $this->user_dir($user_id);

        if (!$this->ensure_dir($dir)) {
            $this->redirect_with_message(false, 'Upload directory is not writable.');
        }

        $allowed = $this->allowed_mimes();

        $files = $_FILES[self::FORM_FIELD];

        $is_multi = is_array($files['name']);
        $items = [];

        if ($is_multi) {
            $count = count($files['name']);
            for ($i = 0; $i < $count; $i++) {
                $items[] = [
                    'name' => $files['name'][$i] ?? '',
                    'type' => $files['type'][$i] ?? '',
                    'tmp_name' => $files['tmp_name'][$i] ?? '',
                    'error' => $files['error'][$i] ?? UPLOAD_ERR_NO_FILE,
                    'size' => $files['size'][$i] ?? 0,
                ];
            }
        } else {
            $items[] = [
                'name' => $files['name'] ?? '',
                'type' => $files['type'] ?? '',
                'tmp_name' => $files['tmp_name'] ?? '',
                'error' => $files['error'] ?? UPLOAD_ERR_NO_FILE,
                'size' => $files['size'] ?? 0,
            ];
        }

        $saved = 0;
        $errors = [];

        foreach ($items as $item) {
            $orig_name = (string)$item['name'];

            if ((int)$item['error'] !== UPLOAD_ERR_OK) {
                if ((int)$item['error'] !== UPLOAD_ERR_NO_FILE) {
                    $errors[] = $orig_name . ' (upload error)';
                }
                continue;
            }

            if (empty($item['tmp_name']) || !is_uploaded_file($item['tmp_name'])) {
                $errors[] = $orig_name . ' (invalid upload)';
                continue;
            }

            $size = (int)$item['size'];
            if ($size <= 0) {
                $errors[] = $orig_name . ' (empty file)';
                continue;
            }
            if ($size > $max_bytes) {
                $errors[] = $orig_name . ' (exceeds max size)';
                continue;
            }

            $ext = $this->file_ext_from_name($orig_name);
            if (!$ext || !isset($allowed[$ext])) {
                $errors[] = $orig_name . ' (file type not allowed)';
                continue;
            }

            $finfo_mime = '';
            if (function_exists('finfo_open')) {
                $finfo = finfo_open(FILEINFO_MIME_TYPE);
                if ($finfo) {
                    $finfo_mime = (string)finfo_file($finfo, $item['tmp_name']);
                    finfo_close($finfo);
                }
            }

            $expected_mime = $allowed[$ext];
            if ($finfo_mime !== '' && $expected_mime !== $finfo_mime) {
                $ok_mismatch = false;
                if (str_starts_with($expected_mime, 'image/') && str_starts_with($finfo_mime, 'image/')) $ok_mismatch = true;
                if ($expected_mime === 'application/msword' && in_array($finfo_mime, ['application/msword','application/octet-stream'], true)) $ok_mismatch = true;
                if (in_array($expected_mime, [
                    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                ], true) && in_array($finfo_mime, ['application/zip','application/octet-stream', $expected_mime], true)) $ok_mismatch = true;

                if (!$ok_mismatch) {
                    $errors[] = $orig_name . ' (mime mismatch)';
                    continue;
                }
            }

            $final_name = $this->unique_filename($dir, $orig_name);
            $dest = trailingslashit($dir) . $final_name;

            if (!@move_uploaded_file($item['tmp_name'], $dest)) {
                $errors[] = $orig_name . ' (could not save)';
                continue;
            }

            @chmod($dest, 0644);

            if ($type === 'profile') {
                update_user_meta($user_id, 'mufu_profile_picture', $final_name);
            } else {
                $list = get_user_meta($user_id, 'mufu_documents', true);
                if (!is_array($list)) $list = [];
                $list[] = $final_name;
                $list = array_values(array_unique(array_filter($list)));
                update_user_meta($user_id, 'mufu_documents', $list);
            }

            $saved++;
        }

        if ($saved > 0 && empty($errors)) {
            $this->redirect_with_message(true, 'Upload successful.');
        } elseif ($saved > 0 && !empty($errors)) {
            $this->redirect_with_message(true, 'Some files uploaded. Issues: ' . implode('; ', $errors));
        } else {
            $this->redirect_with_message(false, 'Upload failed. ' . (!empty($errors) ? implode('; ', $errors) : ''));
        }
    }

    public function handle_delete() {
        if (empty($_GET['mufu_action']) || $_GET['mufu_action'] !== 'delete') return;
        if (!is_user_logged_in()) return;

        $nonce = isset($_GET[self::NONCE_FIELD]) ? sanitize_text_field(wp_unslash($_GET[self::NONCE_FIELD])) : '';
        if (!$nonce || !wp_verify_nonce($nonce, self::NONCE_ACTION)) {
            $this->redirect_with_message(false, 'Security check failed.');
        }

        $type = isset($_GET['mufu_type']) ? sanitize_text_field(wp_unslash($_GET['mufu_type'])) : 'document';
        if (!in_array($type, ['document','profile'], true)) $type = 'document';

        $file = isset($_GET['mufu_file']) ? sanitize_text_field(wp_unslash($_GET['mufu_file'])) : '';
        $file = $this->sanitize_filename_strict($file);
        if ($file === '') $this->redirect_with_message(false, 'Invalid file.');

        $user_id = get_current_user_id();
        [$dir, $url] = $this->user_dir($user_id);
        $path = trailingslashit($dir) . $file;

        if (!file_exists($path)) {
            $this->redirect_with_message(false, 'File not found.');
        }

        if ($type === 'profile') {
            $current = (string)get_user_meta($user_id, 'mufu_profile_picture', true);
            if ($current !== $file) $this->redirect_with_message(false, 'Not allowed.');
            @unlink($path);
            delete_user_meta($user_id, 'mufu_profile_picture');
            $this->redirect_with_message(true, 'Profile picture removed.');
        } else {
            $list = get_user_meta($user_id, 'mufu_documents', true);
            if (!is_array($list)) $list = [];
            if (!in_array($file, $list, true)) $this->redirect_with_message(false, 'Not allowed.');
            @unlink($path);
            $list = array_values(array_diff($list, [$file]));
            update_user_meta($user_id, 'mufu_documents', $list);
            $this->redirect_with_message(true, 'Document removed.');
        }
    }

    private function render_user_files_list($type) {
        $user_id = get_current_user_id();
        [$dir, $url] = $this->user_dir($user_id);

        $out = '<div class="mufu-list">';
        if ($type === 'profile') {
            $file = (string)get_user_meta($user_id, 'mufu_profile_picture', true);
            if ($file) {
                $file_safe = esc_html($file);
                $file_url = esc_url(trailingslashit($url) . rawurlencode($file));
                $delete_url = esc_url(add_query_arg([
                    'mufu_action' => 'delete',
                    'mufu_type' => 'profile',
                    'mufu_file' => rawurlencode($file),
                    self::NONCE_FIELD => wp_create_nonce(self::NONCE_ACTION),
                ]));
                $img = '';
                $ext = $this->file_ext_from_name($file);
                if (in_array($ext, ['jpg','jpeg','png','gif','webp'], true)) {
                    $img = '<div style="margin:10px 0;"><img src="'.$file_url.'" alt="" style="max-width:160px;height:auto;border:1px solid #ddd;padding:4px;background:#fff;"></div>';
                }
                $out .= '<h4>Current Profile Picture</h4>';
                $out .= $img;
                $out .= '<div class="mufu-item"><div><a href="'.$file_url.'" target="_blank" rel="noopener">'.$file_safe.'</a></div><div><a class="mufu-btn" href="'.$delete_url.'">Delete</a></div></div>';
            } else {
                $out .= '<h4>Current Profile Picture</h4><div class="mufu-meta">None uploaded.</div>';
            }
        } else {
            $list = get_user_meta($user_id, 'mufu_documents', true);
            if (!is_array($list)) $list = [];
            $list = array_values(array_unique(array_filter(array_map('strval', $list))));

            $out .= '<h4>Your Documents</h4>';
            if (empty($list)) {
                $out .= '<div class="mufu-meta">No documents uploaded.</div>';
            } else {
                foreach ($list as $file) {
                    $file = $this->sanitize_filename_strict($file);
                    if ($file === '') continue;
                    $path = trailingslashit($dir) . $file;
                    if (!file_exists($path)) continue;

                    $file_safe = esc_html($file);
                    $file_url = esc_url(trailingslashit($url) . rawurlencode($file));
                    $size = @filesize($path);
                    $size_txt = ($size !== false) ? size_format((int)$size) : '';
                    $delete_url = esc_url(add_query_arg([
                        'mufu_action' => 'delete',
                        'mufu_type' => 'document',
                        'mufu_file' => rawurlencode($file),
                        self::NONCE_FIELD => wp_create_nonce(self::NONCE_ACTION),
                    ]));

                    $meta = $size_txt ? '<div class="mufu-meta">'.$size_txt.'</div>' : '';
                    $out .= '<div class="mufu-item"><div><a href="'.$file_url.'" target="_blank" rel="noopener">'.$file_safe.'</a>'.$meta.'</div><div><a class="mufu-btn" href="'.$delete_url.'">Delete</a></div></div>';
                }
            }
        }

        $out .= '</div>';
        return $out;
    }
